<script setup lang="ts">
import type { ItineraryItem } from '../types'
defineProps<{ modelValue:boolean; mode:'form'|'batch'; day:string; days:{date:string;entries:ItineraryItem[]}[]; entries:ItineraryItem[]; selectedIds:string[]; batchCount:number; formatDate:(date:string)=>string }>()
const emit=defineEmits<{ 'update:modelValue':[value:boolean]; 'update:day':[value:string]; toggle:[item:ItineraryItem]; clear:[]; confirm:[] }>()
</script>
<template><el-dialog :model-value="modelValue" :title="mode==='batch'?'將商品加入關聯行程':'選擇關聯行程'" class="shopping-itinerary-picker-dialog" width="min(92vw, 620px)" append-to-body @update:model-value="emit('update:modelValue',$event)"><div v-if="days.length" class="shopping-itinerary-picker"><div class="shopping-itinerary-day-select"><label for="shopping-itinerary-day">選擇旅行天數</label><el-select id="shopping-itinerary-day" :model-value="day" aria-label="選擇旅行天數" @update:model-value="emit('update:day',$event)"><el-option v-for="(item,index) in days" :key="item.date" :label="`第 ${index+1} 天・${formatDate(item.date)}`" :value="item.date" /></el-select></div><div class="shopping-itinerary-picker-heading"><strong>{{ formatDate(day) }}</strong><span>{{ mode==='batch'?`將 ${batchCount} 項商品加入行程`:`${entries.length} 個可選行程` }}</span></div><div class="shopping-itinerary-picker-list"><button v-for="entry in entries" :key="entry.id" type="button" class="shopping-itinerary-picker-row" :class="{'is-selected':selectedIds.includes(entry.id)}" @click="emit('toggle',entry)"><strong>{{ entry.title }}</strong><span>{{ entry.time||'未排時間' }}<template v-if="entry.endTime">－{{entry.endTime}}</template></span><span>{{selectedIds.includes(entry.id)?'已勾選':'選擇'}}</span></button></div></div><div v-else class="shopping-itinerary-picker-empty"><strong>尚未建立可關聯的行程</strong><p>先在每日行程中建立行程後，再回來關聯商品。</p></div><template #footer><el-button @click="emit('update:modelValue',false)">取消</el-button><el-button v-if="selectedIds.length" @click="emit('clear')">清除{{mode==='batch'?'選取':'關聯'}}</el-button><el-button type="primary" @click="emit('confirm')">{{mode==='batch'?'加入關聯行程':'確認關聯'}}{{selectedIds.length?`（${selectedIds.length}）`:''}}</el-button></template></el-dialog></template>
